import{_ as d,o as a,c as l,ag as r}from"./chunks/framework.Vng7Hdlh.js";const p=JSON.parse('{"title":"4. メニュー管理","description":"","frontmatter":{},"headers":[],"relativePath":"internal/features/04-menu.md","filePath":"internal/features/04-menu.md"}'),i={name:"internal/features/04-menu.md"};function o(e,t,h,n,s,c){return a(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="_4-メニュー管理" tabindex="-1">4. メニュー管理 <a class="header-anchor" href="#_4-メニュー管理" aria-label="Permalink to &quot;4. メニュー管理&quot;">​</a></h1><p>メニュー管理では、お客さんに表示するメニューの作成・編集・品切れ管理を行います。POSLAのメニューは「本部テンプレート → 店舗オーバーライド」の2層構造になっており、本部で統一メニューを管理しつつ、店舗ごとに価格や表示をカスタマイズできます。</p><p>管理ダッシュボードの**「メニュー管理」タブ**をクリックし、サブタブを選択して操作します。</p><h2 id="_4-1-カテゴリ管理" tabindex="-1">4.1 カテゴリ管理 <a class="header-anchor" href="#_4-1-カテゴリ管理" aria-label="Permalink to &quot;4.1 カテゴリ管理&quot;">​</a></h2><p>カテゴリは、メニューをグループ分けする単位です。セルフオーダー画面やハンディPOS画面でカテゴリごとにメニューが表示されます。</p><p><strong>サブタブ：「カテゴリ管理」</strong></p><h3 id="カテゴリの作成" tabindex="-1">カテゴリの作成 <a class="header-anchor" href="#カテゴリの作成" aria-label="Permalink to &quot;カテゴリの作成&quot;">​</a></h3><ol><li>「カテゴリ管理」サブタブを開く</li><li><strong>「カテゴリ追加」ボタン</strong>を押す</li><li>モーダルが開く</li><li>以下を入力する：</li></ol><table tabindex="0"><thead><tr><th>項目</th><th>必須</th><th>説明</th><th>入力例</th></tr></thead><tbody><tr><td>カテゴリ名</td><td>✓</td><td>日本語の表示名</td><td>前菜</td></tr><tr><td>カテゴリ名（英語）</td><td>—</td><td>英語の表示名。多言語対応時に使用</td><td>Appetizers</td></tr></tbody></table><ol start="5"><li><strong>保存</strong>ボタンを押す</li><li>カテゴリ一覧に追加される</li></ol><h3 id="カテゴリの編集" tabindex="-1">カテゴリの編集 <a class="header-anchor" href="#カテゴリの編集" aria-label="Permalink to &quot;カテゴリの編集&quot;">​</a></h3><ol><li>カテゴリ一覧で、編集したいカテゴリの<strong>編集ボタン</strong>（鉛筆アイコン）を押す</li><li>モーダルが開き、現在の値が表示される</li><li>以下を変更できる： <ul><li>カテゴリ名</li><li>カテゴリ名（英語）</li><li>表示順序（数値。小さいほど上に表示）</li></ul></li><li><strong>保存</strong>ボタンを押す</li></ol><h3 id="カテゴリの削除" tabindex="-1">カテゴリの削除 <a class="header-anchor" href="#カテゴリの削除" aria-label="Permalink to &quot;カテゴリの削除&quot;">​</a></h3><ol><li>削除したいカテゴリの<strong>削除ボタン</strong>（ゴミ箱アイコン）を押す</li><li>確認ダイアログが表示される</li><li><strong>OK</strong>を押すと削除される</li></ol><div class="warning custom-block"><p class="custom-block-title">注意</p><p>カテゴリを削除すると、そのカテゴリに属するメニューは「カテゴリなし」の状態になります。削除前に、メニューを別のカテゴリに移動させることを推奨します。</p></div><h3 id="カテゴリの並び順" tabindex="-1">カテゴリの並び順 <a class="header-anchor" href="#カテゴリの並び順" aria-label="Permalink to &quot;カテゴリの並び順&quot;">​</a></h3><p>カテゴリの表示順序は「表示順序」の数値で決まります。数値が小さいカテゴリが上（左）に表示されます。セルフオーダー画面・ハンディPOS画面でも同じ順序で表示されます。</p><h2 id="メニューテンプレート" tabindex="-1">メニューテンプレート <a class="header-anchor" href="#メニューテンプレート" aria-label="Permalink to &quot;メニューテンプレート&quot;">​</a></h2><p>メニューテンプレートは、全店舗で共通のマスターメニューです。ここで作成したメニューが全店舗の基本メニューになります。店舗ごとの価格変更や非表示設定は「店舗メニューオーバーライド」で行います。</p><p><strong>サブタブ：「カテゴリ管理」（カテゴリ一覧とメニューが同じ画面に表示されます）</strong></p><h3 id="メニューの作成" tabindex="-1">メニューの作成 <a class="header-anchor" href="#メニューの作成" aria-label="Permalink to &quot;メニューの作成&quot;">​</a></h3><ol><li><strong>「メニュー追加」ボタン</strong>を押す</li><li>モーダルが開く</li><li>以下を入力する：</li></ol><table tabindex="0"><thead><tr><th>項目</th><th>必須</th><th>説明</th><th>入力例</th></tr></thead><tbody><tr><td>メニュー名</td><td>✓</td><td>日本語の表示名</td><td>特製唐揚げ</td></tr><tr><td>メニュー名（英語）</td><td>—</td><td>英語の表示名</td><td>Special Karaage</td></tr><tr><td>カテゴリ</td><td>✓</td><td>ドロップダウンからカテゴリを選択</td><td>メイン料理</td></tr><tr><td>価格（税込）</td><td>✓</td><td>税込価格（円）。0円も可</td><td>880</td></tr><tr><td>説明文</td><td>—</td><td>メニューの詳細説明</td><td>自家製タレで味付けした鶏もも肉...</td></tr><tr><td>説明文（英語）</td><td>—</td><td>英語の説明文</td><td>Chicken thigh marinated in...</td></tr><tr><td>画像</td><td>—</td><td>メニュー写真。ドラッグ＆ドロップまたはクリックでアップロード</td><td>—</td></tr></tbody></table><ol start="4"><li><strong>保存</strong>ボタンを押す</li><li>メニュー一覧に追加される</li></ol><div class="tip custom-block"><p class="custom-block-title">画像について</p><ul><li>対応形式：JPEG、PNG、WebP、GIF</li><li>最大ファイルサイズ：5MB</li><li>アップロード時に自動的に800×800ピクセル以下にリサイズされます（品質0.8のJPEG）</li><li>画像なしでも作成できます。画像なしの場合は🍽️アイコンが表示されます</li></ul></div><h3 id="メニューの編集" tabindex="-1">メニューの編集 <a class="header-anchor" href="#メニューの編集" aria-label="Permalink to &quot;メニューの編集&quot;">​</a></h3><ol><li>メニュー一覧で、編集したいメニューの<strong>編集ボタン</strong>を押す</li><li>モーダルが開き、現在の値が表示される</li><li>各項目を変更する</li><li><strong>品切れ</strong>チェックボックス：チェックを入れると全店舗で品切れ表示になります</li><li><strong>保存</strong>ボタンを押す</li></ol><h3 id="メニューの削除" tabindex="-1">メニューの削除 <a class="header-anchor" href="#メニューの削除" aria-label="Permalink to &quot;メニューの削除&quot;">​</a></h3><ol><li>削除したいメニューの<strong>削除ボタン</strong>を押す</li><li>確認ダイアログが表示される：「このメニューを削除すると、全店舗のオーバーライド設定も削除されます」</li><li><strong>OK</strong>を押すと削除される</li></ol><div class="danger custom-block"><p class="custom-block-title">注意</p><p>メニューテンプレートを削除すると、そのメニューに対する全店舗のオーバーライド設定（価格変更、品切れ状態等）も一緒に削除されます。元に戻せません。</p></div><h3 id="品切れのトグル" tabindex="-1">品切れのトグル <a class="header-anchor" href="#品切れのトグル" aria-label="Permalink to &quot;品切れのトグル&quot;">​</a></h3><p>メニュー一覧の各メニューに<strong>品切れボタン</strong>があります。</p><ul><li><strong>グレー</strong>（通常）→ クリックすると<strong>赤</strong>（品切れ）に変わる</li><li><strong>赤</strong>（品切れ）→ クリックすると<strong>グレー</strong>（通常）に戻る</li><li>品切れにすると、セルフオーダー画面・ハンディPOS画面で即座に「品切れ」表示になり、お客さんは注文できなくなります</li><li>メニューバージョンが自動更新され、お客さんの画面は2秒以内に品切れ状態が反映されます</li></ul><h3 id="カテゴリでフィルター" tabindex="-1">カテゴリでフィルター <a class="header-anchor" href="#カテゴリでフィルター" aria-label="Permalink to &quot;カテゴリでフィルター&quot;">​</a></h3><p>メニュー一覧の上部にカテゴリフィルターのドロップダウンがあります。カテゴリを選択すると、そのカテゴリのメニューだけが表示されます。「全て」を選択すると全メニューが表示されます。</p><h2 id="店舗メニューオーバーライド" tabindex="-1">店舗メニューオーバーライド <a class="header-anchor" href="#店舗メニューオーバーライド" aria-label="Permalink to &quot;店舗メニューオーバーライド&quot;">​</a></h2><p>店舗メニューオーバーライドでは、本部テンプレートのメニューを店舗ごとにカスタマイズします。価格の変更、メニューの非表示、店舗固有の画像設定が可能です。</p><p><strong>サブタブ：「店舗メニュー」</strong></p><div class="warning custom-block"><p class="custom-block-title">店舗を選択してください</p><p>この画面は店舗単位で操作します。ヘッダーの店舗セレクターで、操作したい店舗を選択してから開いてください。</p></div><h3 id="画面の見方" tabindex="-1">画面の見方 <a class="header-anchor" href="#画面の見方" aria-label="Permalink to &quot;画面の見方&quot;">​</a></h3><p>テーブル形式で一覧表示されます。各行に以下の情報があります：</p><table tabindex="0"><thead><tr><th>列</th><th>説明</th></tr></thead><tbody><tr><td>画像</td><td>店舗固有の画像。設定がなければ本部テンプレートの画像</td></tr><tr><td>メニュー名</td><td>名前（日本語/英語）</td></tr><tr><td>カテゴリ</td><td>所属カテゴリ名</td></tr><tr><td>価格</td><td>店舗価格（上書きされている場合はその価格、なければ本部価格）</td></tr><tr><td>非表示</td><td>この店舗でメニューを非表示にするかどうか。非表示の行は半透明（薄い表示）になります</td></tr><tr><td>品切れ</td><td>この店舗での品切れ状態</td></tr><tr><td>操作</td><td>編集・削除ボタン</td></tr></tbody></table><p>「本部品切れ」バッジが表示されている場合、本部テンプレート側で品切れに設定されているため、店舗側で解除できません。</p><h3 id="メニューの価格を変更する" tabindex="-1">メニューの価格を変更する <a class="header-anchor" href="#メニューの価格を変更する" aria-label="Permalink to &quot;メニューの価格を変更する&quot;">​</a></h3><ol><li>変更したいメニューの<strong>編集ボタン</strong>を押す</li><li>モーダルが開く</li><li><strong>価格</strong>欄に新しい価格を入力する（空欄にすると本部価格に戻ります）</li><li><strong>保存</strong>ボタンを押す</li></ol><h3 id="メニューを非表示にする" tabindex="-1">メニューを非表示にする <a class="header-anchor" href="#メニューを非表示にする" aria-label="Permalink to &quot;メニューを非表示にする&quot;">​</a></h3><p>この店舗では提供しないメニューを非表示にできます。</p><ol><li>メニュー一覧で、非表示にしたいメニューの<strong>非表示トグル</strong>を押す</li><li>メニューが半透明表示になり、セルフオーダー画面に表示されなくなります</li><li>もう一度押すと表示に戻ります</li></ol><h3 id="品切れにする" tabindex="-1">品切れにする <a class="header-anchor" href="#品切れにする" aria-label="Permalink to &quot;品切れにする&quot;">​</a></h3><ol><li>メニュー一覧で、品切れにしたいメニューの<strong>品切れトグル</strong>を押す</li><li>赤いバッジが表示され、セルフオーダー画面で品切れ表示になります</li><li>もう一度押すと品切れを解除できます</li></ol><h3 id="カロリー・アレルゲン情報を設定する" tabindex="-1">カロリー・アレルゲン情報を設定する <a class="header-anchor" href="#カロリー・アレルゲン情報を設定する" aria-label="Permalink to &quot;カロリー・アレルゲン情報を設定する&quot;">​</a></h3><p>メニューの編集モーダルで、以下を設定できます：</p><table tabindex="0"><thead><tr><th>項目</th><th>説明</th><th>入力方法</th></tr></thead><tbody><tr><td>カロリー</td><td>kcal単位の数値</td><td>数値入力（例：450）</td></tr><tr><td>アレルゲン</td><td>含まれるアレルゲン</td><td>チェックボックスから選択</td></tr></tbody></table><p><strong>設定可能なアレルゲン（全25項目）：</strong> 卵、乳、小麦、えび、かに、そば、落花生、アーモンド、カシューナッツ、くるみ、ごま、さけ、さば、いか、あわび、いくら、大豆、まつたけ、もも、りんご、キウイ、バナナ、オレンジ、ゼラチン、鶏肉、牛肉、豚肉</p><p>設定したカロリーとアレルゲンはセルフオーダー画面のメニュー詳細に表示されます。</p><h3 id="オプショングループを紐付ける" tabindex="-1">オプショングループを紐付ける <a class="header-anchor" href="#オプショングループを紐付ける" aria-label="Permalink to &quot;オプショングループを紐付ける&quot;">​</a></h3><p>メニューの編集モーダルの下部に、オプショングループの紐付け設定があります。</p><ol><li>編集モーダルを開く</li><li>下部の「オプション」セクションを確認する</li><li>紐付けたいオプショングループに<strong>チェック</strong>を入れる</li><li>「必須」チェックボックス：チェックを入れると、お客さんは注文時にこのオプションを必ず選択する必要があります</li><li><strong>保存</strong>を押す</li></ol><h3 id="店舗固有の画像を設定する" tabindex="-1">店舗固有の画像を設定する <a class="header-anchor" href="#店舗固有の画像を設定する" aria-label="Permalink to &quot;店舗固有の画像を設定する&quot;">​</a></h3><ol><li>編集モーダルを開く</li><li><strong>画像アップロード</strong>エリアに画像をドラッグ＆ドロップ、またはクリックして選択</li><li>プレビューが表示される</li><li><strong>保存</strong>を押す</li><li>この店舗では、本部テンプレートの画像の代わりにこの画像が表示されます</li></ol><h2 id="店舗限定メニュー" tabindex="-1">店舗限定メニュー <a class="header-anchor" href="#店舗限定メニュー" aria-label="Permalink to &quot;店舗限定メニュー&quot;">​</a></h2><p>店舗限定メニューは、特定の店舗でのみ提供するオリジナルメニューです。本部テンプレートには存在しない、その店舗だけのメニューを作成できます。</p><p><strong>サブタブ：「限定メニュー」</strong></p><h3 id="限定メニューの作成" tabindex="-1">限定メニューの作成 <a class="header-anchor" href="#限定メニューの作成" aria-label="Permalink to &quot;限定メニューの作成&quot;">​</a></h3><ol><li><strong>「メニュー追加」ボタン</strong>を押す</li><li>モーダルが開く</li><li>以下を入力する：</li></ol><table tabindex="0"><thead><tr><th>項目</th><th>必須</th><th>説明</th></tr></thead><tbody><tr><td>メニュー名</td><td>✓</td><td>日本語の表示名</td></tr><tr><td>メニュー名（英語）</td><td>—</td><td>英語の表示名</td></tr><tr><td>カテゴリ</td><td>✓</td><td>ドロップダウンから選択</td></tr><tr><td>価格（税込）</td><td>✓</td><td>税込価格（円）</td></tr><tr><td>説明文</td><td>—</td><td>メニューの詳細説明</td></tr><tr><td>画像</td><td>—</td><td>メニュー写真</td></tr><tr><td>カロリー</td><td>—</td><td>kcal（数値）</td></tr><tr><td>アレルゲン</td><td>—</td><td>25項目のチェックボックスから選択</td></tr><tr><td>オプショングループ</td><td>—</td><td>紐付けるオプション</td></tr></tbody></table><ol start="4"><li><strong>保存</strong>ボタンを押す</li><li>メニュー一覧に「限定」バッジ付きで追加される</li></ol><p>限定メニューはセルフオーダー画面で通常のメニューと同様に表示されます（「限定」バッジは管理画面のみの表示で、お客さん側には表示されません）。</p><h3 id="品切れにする-1" tabindex="-1">品切れにする <a class="header-anchor" href="#品切れにする-1" aria-label="Permalink to &quot;品切れにする&quot;">​</a></h3><p>テンプレートメニューと同様に、品切れトグルボタンで切り替えます。</p><h2 id="オプション・トッピング" tabindex="-1">オプション・トッピング <a class="header-anchor" href="#オプション・トッピング" aria-label="Permalink to &quot;オプション・トッピング&quot;">​</a></h2><p>オプショングループは、メニューに付加する選択肢（トッピング、サイズ、焼き加減など）を管理する機能です。</p><p><strong>サブタブ：「オプション管理」</strong></p><h3 id="オプショングループの作成" tabindex="-1">オプショングループの作成 <a class="header-anchor" href="#オプショングループの作成" aria-label="Permalink to &quot;オプショングループの作成&quot;">​</a></h3><ol><li><strong>「グループ追加」ボタン</strong>を押す</li><li>モーダルが開く</li><li>以下を入力する：</li></ol><table tabindex="0"><thead><tr><th>項目</th><th>必須</th><th>説明</th><th>入力例</th></tr></thead><tbody><tr><td>グループ名</td><td>✓</td><td>日本語名</td><td>サイズ</td></tr><tr><td>グループ名（英語）</td><td>—</td><td>英語名</td><td>Size</td></tr><tr><td>選択タイプ</td><td>✓</td><td>「単一選択」または「複数選択」</td><td>単一選択</td></tr><tr><td>最小選択数</td><td>—</td><td>必須選択の最小数</td><td>1</td></tr><tr><td>最大選択数</td><td>—</td><td>選択できる最大数</td><td>1</td></tr></tbody></table><ol start="4"><li><strong>保存</strong>ボタンを押す</li></ol><p><strong>選択タイプの違い：</strong></p><table tabindex="0"><thead><tr><th>タイプ</th><th>動作</th><th>自動設定</th><th>例</th></tr></thead><tbody><tr><td>単一選択</td><td>ラジオボタン形式。1つだけ選択</td><td>最小=1、最大=1</td><td>サイズ（S/M/L）</td></tr><tr><td>複数選択</td><td>チェックボックス形式。0〜N個選択</td><td>最小=0、最大=3</td><td>トッピング（チーズ/卵/ベーコン）</td></tr></tbody></table><h3 id="選択肢の追加" tabindex="-1">選択肢の追加 <a class="header-anchor" href="#選択肢の追加" aria-label="Permalink to &quot;選択肢の追加&quot;">​</a></h3><p>オプショングループを作成したら、そのグループに選択肢を追加します。</p><ol><li>グループのカード内にある**「選択肢追加」ボタン**を押す</li><li>モーダルが開く</li><li>以下を入力する：</li></ol><table tabindex="0"><thead><tr><th>項目</th><th>必須</th><th>説明</th><th>入力例</th></tr></thead><tbody><tr><td>選択肢名</td><td>✓</td><td>日本語名</td><td>Lサイズ</td></tr><tr><td>選択肢名（英語）</td><td>—</td><td>英語名</td><td>Large</td></tr><tr><td>価格差（円）</td><td>—</td><td>追加料金。マイナスも可</td><td>+200</td></tr><tr><td>デフォルト</td><td>—</td><td>チェックすると初期選択される</td><td>—</td></tr></tbody></table><ol start="4"><li><strong>保存</strong>を押す</li></ol><h3 id="グループの有効-無効" tabindex="-1">グループの有効/無効 <a class="header-anchor" href="#グループの有効-無効" aria-label="Permalink to &quot;グループの有効/無効&quot;">​</a></h3><p>グループの編集モーダルに「有効」チェックボックスがあります。無効にすると、そのグループが紐付けられたメニューでもオプション選択が表示されなくなります。</p><div class="tip custom-block"><p class="custom-block-title">使いどころ</p><p>季節限定のトッピングを一時的に無効にしたい場合や、在庫切れのオプションを停止したい場合に使います。紐付け自体を削除する必要はありません。</p></div><h2 id="カロリー・アレルゲン情報" tabindex="-1">カロリー・アレルゲン情報 <a class="header-anchor" href="#カロリー・アレルゲン情報" aria-label="Permalink to &quot;カロリー・アレルゲン情報&quot;">​</a></h2><p>カロリーとアレルゲンの設定方法は「店舗メニューオーバーライド」の編集モーダルで行います。詳細は<a href="#店舗メニューオーバーライド">4.3 店舗メニューオーバーライド</a>を参照してください。</p><p>設定した情報は、セルフオーダー画面のメニュー詳細ポップアップに表示されます。アレルゲンはアイコン付きで表示され、お客さんがアレルギーを持つ食材を含むメニューを避けるのに役立ちます。</p><h2 id="今日のおすすめ" tabindex="-1">今日のおすすめ <a class="header-anchor" href="#今日のおすすめ" aria-label="Permalink to &quot;今日のおすすめ&quot;">​</a></h2><p>「今日のおすすめ」は、日替わりで特定のメニューをセルフオーダー画面の上部に目立つように表示する機能です。</p><p><strong>サブタブ：「店舗メニュー」内のおすすめセクション</strong></p><h3 id="おすすめの追加" tabindex="-1">おすすめの追加 <a class="header-anchor" href="#おすすめの追加" aria-label="Permalink to &quot;おすすめの追加&quot;">​</a></h3><ol><li>「店舗メニュー」サブタブを開く</li><li>おすすめセクションのフォームが表示されている</li><li>以下を設定する：</li></ol><table tabindex="0"><thead><tr><th>項目</th><th>必須</th><th>説明</th></tr></thead><tbody><tr><td>メニュー</td><td>✓</td><td>ドロップダウンからメニューを選択（テンプレート＋限定メニュー両方表示。限定メニューは [限定] タグ付き）</td></tr><tr><td>バッジ種別</td><td>✓</td><td>おすすめ / 人気 / 新着 / 限定 / 本日限り の5種類から選択</td></tr><tr><td>コメント</td><td>—</td><td>最大200文字のひとこと説明（例：「本日入荷の新鮮素材で作りました」）</td></tr></tbody></table><ol start="4"><li><strong>追加</strong>ボタンを押す</li><li>おすすめ一覧にカードが追加される</li></ol><h3 id="おすすめの削除" tabindex="-1">おすすめの削除 <a class="header-anchor" href="#おすすめの削除" aria-label="Permalink to &quot;おすすめの削除&quot;">​</a></h3><ol><li>削除したいおすすめカードの**×ボタン**を押す</li><li>確認ダイアログで<strong>OK</strong>を押す</li><li>おすすめから削除される</li></ol><div class="info custom-block"><p class="custom-block-title">自動リセット</p><p>おすすめは日付ごとに管理されています。翌日になると自動的にリセットされるわけではないので、毎日手動で更新する必要があります。前日のおすすめを削除し、新しいおすすめを追加してください。</p></div><h2 id="品切れ管理" tabindex="-1">品切れ管理 <a class="header-anchor" href="#品切れ管理" aria-label="Permalink to &quot;品切れ管理&quot;">​</a></h2><p>品切れの設定は以下の3箇所から行えます：</p><table tabindex="0"><thead><tr><th>場所</th><th>範囲</th><th>操作者</th></tr></thead><tbody><tr><td>メニューテンプレート（カテゴリ管理タブ）</td><td><strong>全店舗</strong>で品切れ</td><td>マネージャー以上</td></tr><tr><td>店舗メニューオーバーライド（店舗メニュータブ）</td><td><strong>その店舗のみ</strong>品切れ</td><td>マネージャー以上</td></tr><tr><td>KDS画面</td><td><strong>その店舗のみ</strong>品切れ</td><td>KDS操作者</td></tr></tbody></table><p>品切れ設定の反映は即時です。セルフオーダー画面は2秒ごとにメニューバージョンをチェックしており、品切れ設定が変更されるとお客さんの画面に自動反映されます。</p><div class="tip custom-block"><p class="custom-block-title">在庫管理との連動</p><p>在庫管理機能（proプラン以上）を使用している場合、食材の在庫が0になるとそれを使用するメニューが自動的に品切れ表示になります。</p></div><h2 id="メニュー多言語対応" tabindex="-1">メニュー多言語対応 <a class="header-anchor" href="#メニュー多言語対応" aria-label="Permalink to &quot;メニュー多言語対応&quot;">​</a></h2><p>proプラン以上で利用できます。メニューを指定した言語に一括翻訳する機能です。</p><ol><li>「店舗メニュー」サブタブを開く</li><li><strong>「翻訳」ボタン</strong>を押す</li><li>翻訳先の言語を選択する</li><li>全カテゴリ・全メニュー名・全説明文・全オプション名が一括でAI翻訳されます</li><li>翻訳結果はキャッシュに保存され、セルフオーダー画面でお客さんの端末の言語設定に応じて自動表示されます</li></ol><div class="info custom-block"><p class="custom-block-title">翻訳の仕組み</p><p>翻訳にはGemini 2.0 Flash APIを使用しています。30件ごとにバッチ処理されます。翻訳結果は <code>menu_translations</code> テーブルに保存（キャッシュ）され、同じメニューの再翻訳はキャッシュが使われます。メニュー名を変更した場合は再翻訳が必要です。</p></div><h2 id="csv一括インポート・エクスポート" tabindex="-1">CSV一括インポート・エクスポート <a class="header-anchor" href="#csv一括インポート・エクスポート" aria-label="Permalink to &quot;CSV一括インポート・エクスポート&quot;">​</a></h2><p>メニュー関連のデータをCSVファイルで一括管理できます。</p><h3 id="エクスポート-書き出し" tabindex="-1">エクスポート（書き出し） <a class="header-anchor" href="#エクスポート-書き出し" aria-label="Permalink to &quot;エクスポート（書き出し）&quot;">​</a></h3><ol><li>対象のサブタブを開く（店舗メニュー、限定メニュー等）</li><li><strong>「CSVエクスポート」ボタン</strong>を押す</li><li>CSVファイルがダウンロードされます</li><li>ファイルはUTF-8（BOM付き）エンコーディングで、Excelでそのまま開けます</li></ol><h3 id="インポート-読み込み" tabindex="-1">インポート（読み込み） <a class="header-anchor" href="#インポート-読み込み" aria-label="Permalink to &quot;インポート（読み込み）&quot;">​</a></h3><ol><li>対象のサブタブを開く</li><li><strong>「CSVインポート」ボタン</strong>を押す</li><li>CSVファイルを選択する</li><li>インポートが実行される</li><li>結果が表示される：作成された件数、更新された件数、エラーがあればエラー内容</li></ol><div class="warning custom-block"><p class="custom-block-title">CSVインポートの注意点</p><ul><li>インポートはUPSERT方式です（既存のデータがあれば更新、なければ新規作成）</li><li>トランザクション内で実行されるため、途中でエラーがあった場合は全件ロールバックされます</li><li>エラーがあった場合、「行2: カテゴリが見つかりません」のように行番号とエラー内容が表示されます</li></ul></div><h3 id="csvインポート-エクスポート対象" tabindex="-1">CSVインポート/エクスポート対象 <a class="header-anchor" href="#csvインポート-エクスポート対象" aria-label="Permalink to &quot;CSVインポート/エクスポート対象&quot;">​</a></h3><table tabindex="0"><thead><tr><th>データ</th><th>エクスポート</th><th>インポート</th></tr></thead><tbody><tr><td>店舗限定メニュー</td><td>✓</td><td>✓</td></tr><tr><td>メニューオーバーライド</td><td>✓</td><td>✓</td></tr><tr><td>食べ放題プラン</td><td>✓</td><td>✓</td></tr><tr><td>プラン専用メニュー</td><td>✓</td><td>✓</td></tr><tr><td>コース＋フェーズ</td><td>✓</td><td>✓</td></tr><tr><td>食材マスタ</td><td>✓</td><td>✓</td></tr><tr><td>レシピ（BOM）</td><td>✓</td><td>✓</td></tr></tbody></table>',118)])])}const u=d(i,[["render",o]]);export{p as __pageData,u as default};
